module top_module(
    input [7:0] data_i,
    input [2:0] shift_i,
    output [2:0] data_o
    );reg [15:0] shifter_reg;
   always @*
      case (shift_i)
         3'b000: shifter_reg = data_i;
         3'b001: shifter_reg = data_i << 1;
         3'b010: shifter_reg = data_i << 2;
         3'b011: shifter_reg = data_i << 3;
         3'b100: shifter_reg = data_i << 4;
         3'b101: shifter_reg = data_i << 5;
         3'b110: shifter_reg = data_i << 6;
         default: shifter_reg = data_i << 7;
      endcase
	assign data_o = shifter_reg[7:5];endmodule
